import type { Column } from "elements";
import { h, type VNode } from "vue";
import type { Order, OrderStatus, OrderColumnHandlers } from "./types";

const statusLabels: Record<OrderStatus, string> = {
  pending: "Pending",
  processing: "Processing",
  shipped: "Shipped",
  delivered: "Delivered",
  cancelled: "Cancelled",
};

const statusClasses: Record<OrderStatus, string> = {
  pending: "bg-yellow-100 text-yellow-800",
  processing: "bg-blue-100 text-blue-800",
  shipped: "bg-purple-100 text-purple-800",
  delivered: "bg-green-100 text-green-800",
  cancelled: "bg-red-100 text-red-800",
};

const totalFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

const dateFormatter = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

export const createColumns = (handlers: OrderColumnHandlers): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }) => {
      const orderId = String(row.getValue("id"));
      return h("span", { class: "font-mono" }, `#ORD-${orderId}`);
    },
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    cell: ({ row }) => {
      const status = row.getValue("status") as OrderStatus;
      const label = statusLabels[status];
      const classes = statusClasses[status];
      return h(
        "span",
        {
          class: `inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${classes}`,
        },
        label,
      );
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ row }) => {
      const amount = Number(row.getValue("total"));
      const formatted = totalFormatter.format(amount);
      return h("div", { class: "text-right font-medium" }, formatted);
    },
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ row }) => {
      const rawDate = String(row.getValue("date"));
      const formatted = dateFormatter.format(new Date(rawDate));
      return h("span", { class: "text-sm text-gray-600" }, formatted);
    },
  },
  {
    id: "actions",
    cell: ({ row }) => {
      const order = row.original;
      return [
        h(
          "span",
          { class: "inline-flex items-center" },
          { default: () => [
            h(
              "button",
              {
                class: "px-2 py-1 text-xs font-medium text-gray-600 hover:text-gray-900",
                onClick: () => handlers.onView(order),
              },
              "View",
            ),
            h("span", { class: "mx-2 text-gray-300" }, "|"),
            h(
              "button",
              {
                class: "px-2 py-1 text-xs font-medium text-red-600 hover:text-red-900",
                onClick: () => handlers.onCancel(order),
              },
              "Cancel",
            ),
          ]},
        ),
      ] as VNode[];
    },
  },
];

