  {
    id: "id",
    label: "Order",
    cell: ({ record }: { record: Record<Order> }) => {
      return h("span", { style: "font-family: monospace" }, `#ORD-${record.original.id}`);
    },
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    isSortable: true,
    cell: ({ record }: { record: Record<Order> }) => {
      const status = record.original.status;
      return h(
        "span",
        {
          class: statusClasses[status],
        },
        statusLabels[status],
      );
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ record }: { record: Record<Order> }) => {
      return currencyFormatter.format(record.original.total);
    },
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ record }: { record: Record<Order> }) => {
      return dateFormatter.format(new Date(record.original.date));
    },
  },
  {
    id: "actions",
    cell: ({ row }: { row: { original: Order } }) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View",
      ),
      h(
        Button,
        {
          variant: "destructive",
          size: "sm",
          onClick: () => handlers.onCancel(row.original),
        },
        () => "Cancel",
      ),
    ],
  },
