  style: "currency",
  currency: "USD",
});

export const createColumns = (handlers: OrderColumnHandlers): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }: CellContext<Order, unknown>) => {
      return h("span", { style: "font-family: monospace" }, `#ORD-${row.original.id}`);
    },
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    isSortable: true,
    cell: ({ row }: CellContext<Order, unknown>) => {
      const status = row.original.status;
      return h(
        "span",
        {
          class: statusClasses[status],
        },
        statusLabels[status],
      );
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ row }: CellContext<Order, unknown>) => {
      return currencyFormatter.format(row.original.total);
    },
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ row }: CellContext<Order, unknown>) => {
      return dateFormatter.format(new Date(row.original.date));
    },
  },
  {
    id: "actions",
    cell: ({ row }: CellContext<Order, unknown>) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View",
