import type { Column } from "elements";
import { Button } from "elements";
import { h } from "vue";
import type { Order, OrderStatus } from "./types";

export interface OrderColumnHandlers {
  onView: (order: Order) => void;
  onCancel: (order: Order) => void;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: "Pending",
  processing: "Processing",
  shipped: "Shipped",
  delivered: "Delivered",
  cancelled: "Cancelled",
};

const STATUS_CLASSES: Record<OrderStatus, string> = {
  pending: "bg-yellow-100 text-yellow-800",
  processing: "bg-blue-100 text-blue-800",
  shipped: "bg-purple-100 text-purple-800",
  delivered: "bg-green-100 text-green-800",
  cancelled: "bg-red-100 text-red-800",
};

const dateFormatter = new Intl.DateTimeFormat("en-US", { dateStyle: "medium" });
const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

export const createColumns = (handlers: OrderColumnHandlers): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    isSortable: false,
    cell: ({ row }) =>
      h("span", { class: "font-mono" }, `#${row.original.id!}`),
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    isSortable: false,
    cell: ({ row }) => {
      const statusClass = STATUS_CLASSES[row.original.status];
      const label = STATUS_LABELS[row.original.status];
      return h("span", { class: `px-2 py-1 rounded-full ${statusClass}` }, label);
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ row }) => h("span", null, currencyFormatter.format(row.original.total)),
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ row }) => h("span", null, dateFormatter.format(new Date(row.original.date))),
  },
  {
    id: "actions",
    label: "Actions",
    isSortable: false,
    cell: ({ row }) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View"
      ),
      h(
        Button,
        {
          variant: "destructive",
          size: "sm",
          onClick: () => handlers.onCancel(row.original),
        },
        () => "Cancel"
      ),
    ],
  },
];

