import type { Column } from "elements";
import { Button } from "elements";
import { h } from "vue";
import type { Order, OrderStatus } from "./types";

export interface OrderColumnHandlers {
  onView: (order: Order) => void;
  onCancel: (order: Order) => void;
}

const statusConfig: Record<OrderStatus, { label: string; class: string }> = {
  pending: { label: "Pending", class: "status-pending" },
  processing: { label: "Processing", class: "status-processing" },
  shipped: { label: "Shipped", class: "status-shipped" },
  delivered: { label: "Delivered", class: "status-delivered" },
  cancelled: { label: "Cancelled", class: "status-cancelled" },
};

const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

const dateFormatter = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

export const createColumns = (
  handlers: OrderColumnHandlers,
): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }) => [
      h("span", { class: "font-mono" }, `#ORD-${row.original.id}`),
    ],
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
    cell: ({ row }) => row.original.customer,
  },
  {
    id: "status",
    label: "Status",
    cell: ({ row }) => {
      const config = statusConfig[row.original.status];
      return h("span", { class: config.class }, config.label);
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
    cell: ({ row }) => row.original.items,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ row }) => currencyFormatter.format(row.original.total),
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ row }) => dateFormatter.format(new Date(row.original.date)),
  },
  {
    id: "actions",
    cell: ({ row }) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View",
